'use client'

import { useEffect, useRef, useState } from 'react'

export default function Home() {

  // STATE
  const [role, setRole] = useState('emp')
  const [email, setEmail] = useState('')
  const [submitted, setSubmitted] = useState(false)
  const [count, setCount] = useState(340)
  const [active, setActive] = useState('summary')
  const [sidebarOpen, setSidebarOpen] = useState(false)

  const sectionsRef = useRef({})

  const C = {
    deep: '#12082E',
    purple: '#7B2FFF',
    border: '#DDD6FF',
    muted: '#5A4880',
    grad: 'linear-gradient(135deg,#7B2FFF,#C084FC)',
  }

  const nav = [
    'summary',
    'competencies',
    'experience',
    'stats',
    'projects',
    'pricing',
    'references'
  ]

  // SCROLL ACTIVE NAV
  useEffect(() => {
    const handleScroll = () => {
      const scrollY = window.scrollY + 80

      Object.entries(sectionsRef.current).forEach(([id, el]) => {
        if (!el) return
        if (scrollY >= el.offsetTop && scrollY < el.offsetTop + el.offsetHeight) {
          setActive(id)
        }
      })
    }

    window.addEventListener('scroll', handleScroll)
    return () => window.removeEventListener('scroll', handleScroll)
  }, [])

  // ANIMATIONS
  useEffect(() => {

    const observer = new IntersectionObserver((entries) => {
      entries.forEach(entry => {
        if (!entry.isIntersecting) return

        entry.target.classList.add('vis')

        // SKILL BARS
        entry.target.querySelectorAll('.skill-fill, .bar-fill').forEach(el => {
          el.style.width = el.dataset.w + '%'
        })

        // DONUTS
        entry.target.querySelectorAll('.donut-ring').forEach(ring => {
          const pct = parseFloat(ring.dataset.pct)
          const circ = 2 * Math.PI * 48
          const offset = circ - (pct / 100) * circ
          ring.style.strokeDasharray = circ
          ring.style.strokeDashoffset = offset
          ring.style.transition = '1.5s'
        })
      })
    }, { threshold: 0.08 })

    document.querySelectorAll('.fu').forEach(el => observer.observe(el))

    // SIDEBAR SKILLS
    setTimeout(() => {
      document.querySelectorAll('.skill-fill').forEach(el => {
        el.style.width = el.dataset.w + '%'
      })
    }, 400)

  }, [])

  const handleSubmit = () => {
    if (!email.includes('@')) return
    setSubmitted(true)
    setCount(c => c + 1)
    setEmail('')
  }

  return (
    <div style={{ display: 'flex' }}>

      {/* MOBILE BUTTON */}
      <button
        onClick={() => setSidebarOpen(!sidebarOpen)}
        style={{
          position: 'fixed',
          top: 16,
          left: 16,
          zIndex: 200,
          width: 40,
          height: 40,
          background: C.deep,
          color: 'white'
        }}
      >≡</button>

      {/* SIDEBAR */}
      <aside style={{
        width: 300,
        background: C.deep,
        color: 'white',
        position: 'fixed',
        top: 0,
        bottom: 0,
        left: sidebarOpen ? 0 : -300,
        padding: 30,
        transition: '0.3s'
      }}>

        <h2>RecSay</h2>

        {nav.map(id => (
          <a
            key={id}
            href={`#${id}`}
            onClick={() => setSidebarOpen(false)}
            style={{
              display: 'block',
              margin: '12px 0',
              color: active === id ? 'white' : '#aaa'
            }}
          >
            {id}
          </a>
        ))}

        {/* SKILLS */}
        {[94, 88, 96, 91, 87].map((v, i) => (
          <div key={i} style={{ marginTop: 10 }}>
            <div>{v}%</div>
            <div style={{ height: 4, background: '#222' }}>
              <div
                className="skill-fill"
                data-w={v}
                style={{
                  width: 0,
                  height: '100%',
                  background: C.grad
                }}
              />
            </div>
          </div>
        ))}

      </aside>

      {/* MAIN */}
      <main style={{
        marginLeft: 300,
        padding: 40,
        width: '100%'
      }}>

        {/* SUMMARY */}
        <section
          id="summary"
          className="fu"
          ref={el => sectionsRef.current.summary = el}
        >
          <h1>RecSay Platform</h1>

          <div>
            <button onClick={() => setRole('emp')}>Employer</button>
            <button onClick={() => setRole('rec')}>Recruiter</button>
          </div>

          <div style={{ marginTop: 20 }}>
            <input
              value={email}
              onChange={e => setEmail(e.target.value)}
              placeholder="Enter email"
            />
            <button onClick={handleSubmit}>Join</button>
          </div>

          {!submitted && <p>{count}+ users</p>}
          {submitted && <p>✓ Added</p>}
        </section>

        {/* COMPETENCIES */}
        <section id="competencies" className="fu" ref={el => sectionsRef.current.competencies = el} style={{ marginTop: 150 }}>
          <h2>Competencies</h2>
        </section>

        {/* EXPERIENCE */}
        <section id="experience" className="fu" ref={el => sectionsRef.current.experience = el} style={{ marginTop: 150 }}>
          <h2>Live Clusters</h2>
        </section>

        {/* STATS */}
        <section id="stats" className="fu" ref={el => sectionsRef.current.stats = el} style={{ marginTop: 150 }}>
          <h2>Stats</h2>

          <svg width="120" height="120">
            <circle cx="60" cy="60" r="48" stroke="#eee" strokeWidth="10" fill="none"/>
            <circle
              className="donut-ring"
              data-pct="90"
              cx="60" cy="60" r="48"
              stroke="purple"
              strokeWidth="10"
              fill="none"
              strokeDasharray="301"
              strokeDashoffset="301"
              transform="rotate(-90 60 60)"
            />
          </svg>
        </section>

        {/* PROJECTS */}
        <section id="projects" className="fu" ref={el => sectionsRef.current.projects = el} style={{ marginTop: 150 }}>
          <h2>Projects</h2>
        </section>

        {/* PRICING */}
        <section id="pricing" className="fu" ref={el => sectionsRef.current.pricing = el} style={{ marginTop: 150 }}>
          <h2>Pricing</h2>
        </section>

        {/* REFERENCES */}
        <section id="references" className="fu" ref={el => sectionsRef.current.references = el} style={{ marginTop: 150 }}>
          <h2>References</h2>
        </section>

      </main>
    </div>
  )
}